function CopilotOverlay({ children, messages }) {
  const { div, main, header, span, section, input: inputEl } = tags;
  const [open, setOpen] = createSignal(false);
  const [mode, setMode] = createSignal('overlay');

  const toggle = () => setOpen(!open());

  // Cmd+K shortcut
  onMount(() => {
    const handler = (e) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        toggle();
      }
    };
    document.addEventListener('keydown', handler);
    onDestroy(() => document.removeEventListener('keydown', handler));
  });

  return div({ class: css('_grid _h[100vh]'), style: () => `grid-template-columns:1fr ${open() && mode() === 'push' ? '360px' : '0'};grid-template-rows:56px 1fr` },
    // Header
    header({ class: css('_flex _aic _jcsb _px4 _borderB _bgbg'), style: 'grid-column:1/3' },
      span({ class: css('_heading4') }, 'App'),
      div({ class: css('_flex _aic _gap2') },
        Button({ variant: 'outline', size: 'sm', onclick: toggle },
          icon('sparkles'), ' Copilot'
        ),
        Avatar({ size: 'sm' })
      )
    ),
    // Body
    main({ class: css('_flex1 _overflow[auto] _p6') },
      ...children
    ),
    // Copilot panel (overlay mode)
    open() ? section({
      class: css('_flex _col _borderL _bgraised _overflow[auto]'),
      style: () => mode() === 'overlay'
        ? 'position:fixed;right:0;top:56px;width:360px;height:calc(100vh - 56px);z-index:40'
        : ''
    },
      div({ class: css('_flex _aic _jcsb _px4 _py3 _borderB') },
        span({ class: css('_fontmedium') }, 'Copilot'),
        Button({ variant: 'ghost', size: 'sm', onclick: toggle }, icon('x'))
      ),
      div({ class: css('_flex1 _overflow[auto] _p4') },
        ...messages
      ),
      div({ class: css('_p3 _borderT') },
        inputEl({ type: 'text', placeholder: 'Ask anything...', class: css('_wfull _p2 _r2 _border') })
      )
    ) : Button({
      variant: 'default',
      size: 'sm',
      class: css('_fixed _bottom6 _right6 _z40 _shadow _r[999px] _px4 _py2'),
      onclick: toggle
    }, icon('sparkles'), ' Ask AI')
  );
}
